import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_distance(p1, p2):
        return np.linalg.norm(p1 - p2)

    def time_to_node(start_pos, end_pos, speed):
        distance = calculate_distance(start_pos, end_pos)
        return distance / speed

    best_node = None
    min_time_cost = float('inf')

    for i, customer in enumerate(unvisited_customers):
        travel_time = time_to_node(cur_truck_pos, customer, truck_speed)
        arrival_time = current_time + travel_time
        window_open, window_close = time_windows[i]

        if arrival_time > window_close:
            penalty_time = (arrival_time - window_close)**2
        elif arrival_time < window_open:
            penalty_time = (window_open - arrival_time) + truck_speed * 0.1  # Slight penalty and advantage to waiting
        else:
            penalty_time = 0  # No penalty if within the time window

        time_cost = arrival_time + penalty_time

        if time_cost < min_time_cost:
            min_time_cost = time_cost
            best_node = i

    if best_node is None:
        return None  # Indicate to wait if no suitable node found
    return best_node
